356	// inspect returns the list of supported architectures for the images used by the pod.
357	// if an error occurs, it returns the error and a nil slice of strings.
358	func (pod *Pod) intersectImagesArchitecture(pullSecretDataList [][]byte) (supportedArchitectures []string, err error) {
359		log := ctrllog.FromContext(pod.Ctx())
360		imageNamesSet := pod.imagesNamesSet()
361		log.V(1).Info("Images list for pod", "imageNamesSet", fmt.Sprintf("%+v", imageNamesSet))
362		// https://github.com/containers/skopeo/blob/v1.11.1/cmd/skopeo/inspect.go#L72
363		// Iterate over the images, get their architectures and intersect (as in set intersection) them each other
364		var supportedArchitecturesSet sets.Set[string]
365		nowExternal := time.Now()
366		defer utils.HistogramObserve(nowExternal, metrics.TimeToInspectPodImages)
367		for imageContainer := range imageNamesSet {
368			log.V(3).Info("Checking image", "imageName", imageContainer.imageName,
369				"skipCache (imagePullPolicy==Always)", imageContainer.skipCache)
370			// We are collecting the time to inspect the image here to avoid implementing a metric in each of the
371			// cache implementations.
372			now := time.Now()
373			currentImageSupportedArchitectures, err := imageInspectionCache.GetCompatibleArchitecturesSet(pod.Ctx(),
374				imageContainer.imageName, imageContainer.skipCache, pullSecretDataList)
375			utils.HistogramObserve(now, metrics.TimeToInspectImage)
376			if err != nil {
377				log.V(1).Error(err, "Error inspecting the image", "imageName", imageContainer.imageName)
378				return nil, err
379			}
380			if supportedArchitecturesSet == nil {
381				supportedArchitecturesSet = currentImageSupportedArchitectures
382			} else {
383				supportedArchitecturesSet = supportedArchitecturesSet.Intersection(currentImageSupportedArchitectures)
384			}
385		}
386		return sets.List(supportedArchitecturesSet), nil
387	}
