427	// shouldIgnorePod returns true if the pod should be ignored by the operator.
428	// The operator should ignore the pods in the following cases:
429	// - the pod is in the same namespace as the operator
430	// - the pod is in a namespace with prefix kube-
431	// - the pod has a node name set
432	// - the pod has a node selector that matches the control plane nodes
433	// - the pod is owned by a DaemonSet
434	// - the pod has required architecture affinity configured AND:
435	//   - preferred affinity is already configured, OR
436	//   - both CPPC and all matching PPCs have the NodeAffinityScoring plugin disabled
437	func (pod *Pod) shouldIgnorePod(cppc *v1beta1.ClusterPodPlacementConfig, matchingPPCs []v1beta1.PodPlacementConfig) bool {
438		return utils.Namespace() == pod.Namespace || strings.HasPrefix(pod.Namespace, "kube-") ||
439			pod.Spec.NodeName != "" || pod.HasControlPlaneNodeSelector() || pod.IsFromDaemonSet() ||
440			pod.isNodeSelectorConfiguredForArchitecture() &&
441				(pod.isPreferredAffinityConfiguredForArchitecture() ||
442					(!cppc.PluginsEnabled(common.NodeAffinityScoringPluginName) && !pod.hasMatchingPPCWithPlugin(matchingPPCs)))
443	}
