497	func (pod *Pod) handleError(err error, s string) {
498		if err == nil {
499			return
500		}
501		log := ctrllog.FromContext(pod.Ctx())
502		metrics.FailedInspectionCounter.Inc()
503		errMsg := err.Error()
504		runes := []rune(errMsg)
505		if len(runes) > 256 {
506			errMsg = string(runes[:256])
507		}
508		pod.EnsureLabel(utils.ImageInspectionErrorLabel, "")
509		pod.EnsureAnnotation(utils.ImageInspectionErrorLabel, errMsg)
510		pod.EnsureAndIncrementLabel(utils.ImageInspectionErrorCountLabel)
